def safe_storage_operation(operation_name):
    """Decorator for wrapping storage operations with standardized error handling"""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except sqlite3.OperationalError as e:
                if "database is locked" in str(e):
                    # Implement exponential backoff retry
                    for attempt in range(3):
                        time.sleep(0.5 * (2 ** attempt))
                        try:
                            return func(*args, **kwargs)
                        except Exception:
                            continue
                    raise ProfileConcurrencyError(f"Database locked during {operation_name}")
                elif "no such table" in str(e):
                    raise ProfileCorruptionError(f"Database schema issue: {e}")
                else:
                    raise ProfileStorageConnectionError(f"Database operation failed: {e}")
            except Exception as e:
                # Log unexpected errors
                logging.error(f"Unexpected error in {operation_name}: {e}", exc_info=True)
                raise
        return wrapper
    return decorator
