class ErrorTelemetry:
    def __init__(self):
        self.error_counts = defaultdict(int)
        self.error_timestamps = defaultdict(list)
        self.lock = threading.RLock()

    def record_error(self, error_type, context=None):
        with self.lock:
            self.error_counts[error_type] += 1
            self.error_timestamps[error_type].append(time.time())
            # Trim old timestamps (keep last 100)
            if len(self.error_timestamps[error_type]) > 100:
                self.error_timestamps[error_type] = self.error_timestamps[error_type][-100:]

    def get_error_rate(self, error_type, time_window=300):
        """Get error rate for specified type in last time_window seconds"""
        with self.lock:
            now = time.time()
            recent_errors = [t for t in self.error_timestamps[error_type] 
                            if now - t <= time_window]
            return len(recent_errors)

    def get_report(self):
        """Generate error summary report"""
        with self.lock:
            return {
                "counts": dict(self.error_counts),
                "rates": {
                    err_type: self.get_error_rate(err_type)
                    for err_type in self.error_counts
                }
            }
