def recover_profile_data(profile_id):
    """Attempt to recover corrupted profile data"""
    # Try primary backup
    try:
        backup_path = f"backups/profiles/{profile_id}.json"
        if os.path.exists(backup_path):
            with open(backup_path, 'r') as f:
                profile_data = json.load(f)
                # Validate recovered data
                if validate_profile_schema(profile_data):
                    return profile_data
    except Exception as e:
        logging.warning(f"Failed to recover from primary backup: {e}")

    # Try point-in-time backups (last 5 days)
    for days_ago in range(1, 6):
        try:
            date_str = (datetime.now() - timedelta(days=days_ago)).strftime("%Y%m%d")
            backup_path = f"backups/profiles/archive/{date_str}/{profile_id}.json"
            if os.path.exists(backup_path):
                with open(backup_path, 'r') as f:
                    profile_data = json.load(f)
                    if validate_profile_schema(profile_data):
                        return profile_data
        except Exception as e:
            logging.warning(f"Failed to recover from {days_ago}-day backup: {e}")

    # If all recovery attempts fail
    raise ProfileCorruptionError(f"Unable to recover data for profile {profile_id}")
