        integrity_check = conn.execute("PRAGMA integrity_check").fetchone()[0]
        if integrity_check != "ok":
            results["status"] = "unhealthy"
            results["issues"].append(f"Integrity check failed: {integrity_check}")
        conn.close()
    except Exception as e:
        results["status"] = "unhealthy"
        results["issues"].append(f"Integrity check error: {str(e)}")

    # Check backup system
    try:
        if not os.path.exists("backups/profiles"):
            results["status"] = "degraded"
            results["issues"].append("Backup directory not found")
    except Exception as e:
        results["status"] = "degraded"
        results["issues"].append(f"Backup check error: {str(e)}")

    return results
