```python
# src/profile_repository.py
import os
import logging

class ProfileRepository:
    # ... existing methods ...

    def perform_storage_health_check(self):
        """
        Performs comprehensive health check on the storage system
        Returns a dictionary with health status information
        """
        results = {
            "status": "healthy",
            "issues": [],
            "checks_performed": []
        }

        # Check 1: Database connection
        try:
            cursor = self.conn.cursor()
            cursor.execute("SELECT 1")
            cursor.fetchone()
            results["checks_performed"].append("connection")
            logging.info("Storage health check: Database connection successful")
        except Exception as e:
            results["status"] = "unhealthy"
            results["issues"].append(f"Connection error: {str(e)}")
            logging.error(f"Storage health check: Connection error - {str(e)}")

        # Check 2: Database integrity
        try:
            cursor = self.conn.cursor()
            integrity_result = cursor.execute("PRAGMA integrity_check").fetchone()[0]
            results["checks_performed"].append("integrity")

            if integrity_result != "ok":
                results["status"] = "unhealthy"
                results["issues"].append(f"Integrity check failed: {integrity_result}")
                logging.error(f"Storage health check: Integrity check failed - {integrity_result}")
            else:
                logging.info("Storage health check: Database integrity verified")
        except Exception as e:
            results["status"] = "unhealthy"
            results["issues"].append(f"Integrity check error: {str(e)}")
            logging.error(f"Storage health check: Integrity check error - {str(e)}")

        # Check 3: Backup directory
        try:
            db_path = self.conn.execute("PRAGMA database_list").fetchone()[2]
            db_dir = os.path.dirname(db_path)
            backup_dir = os.path.join(db_dir, "backups")

            results["checks_performed"].append("backup_directory")

            if not os.path.exists(backup_dir):
                if results["status"] == "healthy":
                    results["status"] = "degraded"
                results["issues"].append("Backup directory not found")
                logging.warning("Storage health check: Backup directory not found")
            else:
                logging.info("Storage health check: Backup directory exists")
        except Exception as e:
            if results["status"] == "healthy":
                results["status"] = "degraded"
            results["issues"].append(f"Backup check error: {str(e)}")
            logging.error(f"Storage health check: Backup check error - {str(e)}")

        logging.info(f"Storage health check complete - Status: {results['status']}")
        return results
